INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00054', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '下列那一句話沒有冗詞贅字？', '["接下來醫生會幫您做一個檢查的動作，請先稍候", "關於這場比賽結果的部分，紅隊險勝了白隊三分", "為了養家，他無時無刻不在工作，最後累出病來", "今天必須回老家一趟，然後已經先跟公司請假了"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00055', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '下列成語應用，何者最為適當？', '["這種無枉無縱的態度，實在不太負責任", "這麼美的風景，瞬間就雲淡風輕地消逝", "祝你這趟環島旅行鵬程萬里，玩得盡興", "家人之間休戚與共，應該一起面對問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00056', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '俗話說：「人生沒有白走的路，每一步都算數。」下列選項，最符合文意的是：', '["做人留一線，日後好相見", "凡是走過的，必留下痕跡", "行到水窮處，坐看雲起時", "路遙知馬力，日久見人心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00057', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '下列文句沒有語病的是：', '["越瞭解自己的人，越能瞭解世界", "再過一會兒我們已經把工作完成", "要預測未來，首先要會展望過去", "這位女星曾經一度在麥當勞打工"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00058', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「我發現跑步與寫作的節奏非常類似。跑五公里其實跟寫五頁的報告很像，都是基礎能力。把五公里 跑好，重心清楚穩定地向前邁進，是關鍵的核心能力。沒能把五公里跑好，歪歪扭扭地跑到十幾公里 也只是傷了膝蓋而已。把一篇五頁的報告寫好也是基礎。」 根據上文，下列選項何者最符合文意？', '["行百里者，半於九十", "讀萬卷書，行萬里路", "千里之行，始於足下", "駑馬十駕，功在不舍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00059', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「我認為老房子改造咖啡館是非常適合的。因為老房子中總是有某種□□□□的氣息，咖啡香的瀰漫， 剛好可以去除那些老房子裡令人不愉快的氣味。」 根據上文，□□□□最為合適的詞語是：', '["環堵蕭然", "無聲無臭", "樸拙簡略", "古老陳腐"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00060', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「為考量競技運動選手培育的長遠規劃及運動科學發展，未來國家運動科學中心的業務，包括辦理國 家優秀運動選手所需之運動科學支援服務、健康管理及醫療照護，並進行國際賽事資訊之分析，亦將 衡酌該中心的量能，進行運動科技之研發、技術移轉及加值應用，提升產業競爭力。同時協助規劃及 培育運動科學人才，將運動科學成果推廣全民運用。」 根據上文，下列選項最符合國家運動科學中心的職責是：', '["培訓競技運動選手", "辦理國際運動賽事", "研擬運動科技新知和應用", "推廣民眾運動與休閒風氣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00061', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '下列選項「」中的成語，何者應用正確？', '["做事一定要有規劃，免得「相形見絀」", "考量時間「綽綽有餘」，我們就晚點出門", "平時不好好讀書，到頭來只能「代人捉刀」", "和他的作品比起來，我的就顯得「左右逢源」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00062', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '澄清公告：「有民眾收到偽冒數位發展部名義發送的詐騙簡訊，數位部已向警方165反詐騙專線完成 報案。為避免日後遭有心人士利用，數位部已經註冊該簡訊之網址，並設定自動導向民間事實查核單 位的澄清說明網頁，以釐清事實，防止假訊息擴散。數位部也提醒民眾，詐騙簡訊所載網址若非gov.tw 結尾，就非政府機關網址，若收到這類詐騙簡訊，務請不要轉傳，造成親友誤解。」 根據上文，下列選項正確的是：', '["數位部已架設反詐騙澄清網頁防止民眾受騙", "只要是政府機關的網址一定會以gov.tw結尾", "詐騙簡訊透過網址轉傳使更多民眾信以為真", "數位部註冊的網址和詐騙簡訊上的網址不同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00063', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-114-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「日治初期來臺日本畫家以傳統繪畫派別為主。他們在工作之餘組織『臺灣書畫會』團體，定期舉辦 書畫會活動並展出作品。他們同時參與報社舉辦的全臺書畫展，作品透過媒體的報導評介而廣為傳播。 臺灣書畫家也透過參與展覽會而與日本畫家交流。許多職業畫家因市場需求、個人興趣或參選日本美 術展覽會所需，尋找日本傳統畫的相關圖冊，積極學習、模仿，畫風也逐漸融合日本畫傳統派別的影 響。」 根據上文，下列選項最符合文意的是：', '["日本畫家通過模仿學習，進而了解不同流派的畫風", "臺灣畫家作品只在日本參展，才有機會打開知名度", "臺灣畫家畫風的轉變，是受日本職業畫家傳統畫風的影響", "臺日畫家可以藉由參與展覽會的方式，互相交流美學風格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:45+00:00", "source_pdf_sha1": "ec3d1305ccbd", "answer_pdf_sha1": "e298021d32ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
